exports.code = async (inputs) => {
    let list = null;

    // 코드 노드에 입력된 모든 변수를 하나씩 뒤집니다.
    for (const key in inputs) {
        let val = inputs[key];

        // 1. 문자열로 들어온 경우 JSON 배열 파싱 시도
        if (typeof val === 'string') {
            try {
                val = JSON.parse(val);
            } catch (e) {}
        }

        // 2. 바로 배열 형태를 찾은 경우 채택
        if (Array.isArray(val)) {
            list = val;
            break;
        }

        // 3. Storage Get 결과 객체 속에서 배열을 찾은 경우 채택
        if (val && typeof val === 'object') {
            if (Array.isArray(val.value)) {
                list = val.value;
                break;
            }
            if (val.key && val.value) {
                let innerVal = val.value;
                if (typeof innerVal === 'string') {
                    try { innerVal = JSON.parse(innerVal); } catch(e) {}
                }
                if (Array.isArray(innerVal)) {
                    list = innerVal;
                    break;
                }
            }
        }
    }

    // 배열을 찾지 못한 경우 빈 배열로 세팅
    if (!list || !Array.isArray(list)) {
        list = [];
    }

    // 중복 제거 처리
    const uniqueList = [...new Set(list)];

    return { list: uniqueList };
};

const axios = require('axios');
const cheerio = require('cheerio');

// 만능 재귀적 키-값 추출기
function findValueByKey(obj, targetKey) {
    if (!obj || typeof obj !== 'object') return undefined;
    if (obj[targetKey] !== undefined) return obj[targetKey];
    for (const key in obj) {
        const val = obj[key];
        if (typeof val === 'string') {
            try {
                const fixedVal = val.replace(/([a-zA-Z0-9_]+)\s*:/g, '"$1":').replace(/'/g, '"');
                const parsed = JSON.parse(fixedVal);
                if (parsed && typeof parsed === 'object') {
                    const found = findValueByKey(parsed, targetKey);
                    if (found !== undefined) return found;
                }
            } catch (e) {
                const cleanVal = val.replace(/\\"/g, '"').replace(/\\'/g, "'");
                const regex = new RegExp(`['"]?${targetKey}['"]?\\s*:\\s*([^\\n,]+)`);
                const match = cleanVal.match(regex);
                if (match) {
                    const strVal = match[1].replace(/[\[\]'"{}\\\\]/g, '').trim();
                    if (strVal) return strVal;
                }
            }
        } else if (val && typeof val === 'object') {
            const found = findValueByKey(val, targetKey);
            if (found !== undefined) return found;
        }
    }
    return undefined;
}

// 4대 플랫폼 크롤러 함수
async function scrapeWorknet(keyword) {
    const encodedKeyword = encodeURIComponent(keyword);
    const url = `https://www.work.go.kr/empInfo/empInfoSrch/list/dtlEmpSrchList.do?searchOn=Y&srcKeyword=${encodedKeyword}`;
    const headers = { "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)" };
    const jobs = [];
    try {
        const response = await axios.get(url, { headers, timeout: 6000 });
        const $ = cheerio.load(response.data);
        $("table.board-list tbody tr").each((i, el) => {
            const row = $(el);
            const company = row.find("a.cp_name").text().trim() || "회사명 비공개";
            const titleElement = row.find(".cp-info a").first();
            if (!titleElement.length) return;
            const title = titleElement.text().trim();
            const link = titleElement.attr('href')?.startsWith('http') ? titleElement.attr('href') : "https://www.work24.go.kr" + titleElement.attr('href');
            const ems = row.find(".cp-info em");
            const address = ems.length ? $(ems[ems.length - 1]).text().trim() : "지역무관";
            jobs.push({ source: "고용24", company, title, address, career: $(ems[0]).text().trim() || "관계없음", education: "무관", detailText: row.text(), url: link });
        });
    } catch (e) {}
    return jobs;
}

async function scrapeIncruit(keyword) {
    // 💡 [수정] 불필요해진 EUC-KR 강제 변환 함수를 제거하고 순정 UTF-8 규격으로 복구
    const encodedKeyword = encodeURIComponent(keyword);
    const url = `https://search.incruit.com/list/search.asp?col=job&kw=${encodedKeyword}`;
    const headers = { "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)" };
    const jobs = [];
    try {
        const response = await axios.get(url, { headers, responseType: 'arraybuffer', timeout: 6000 });
        const decoder = new TextDecoder('euc-kr');
        const $ = cheerio.load(decoder.decode(response.data));
        $("li.c_col").each((i, el) => {
            const col = $(el);
            const company = col.find("div.cell_first a").first().text().trim() || "회사명 비공개";
            const jobAnchor = col.find("div.cell_mid a").first();
            if (!jobAnchor.length) return;
            const title = jobAnchor.text().trim();
            const link = jobAnchor.attr('href')?.startsWith('http') ? jobAnchor.attr('href') : "https://job.incruit.com" + jobAnchor.attr('href');

            // 💡 [핵심 버그 패치] .split(' ')[0] 을 제거하여 "서울 강남구" 전체 텍스트를 온전히 추출
            const address = col.find(".cl_md").text().trim() || "지역무관";

            jobs.push({ source: "인크루트", company, title, address, career: "관계없음", education: "무관", detailText: col.text(), url: link });
        });
    } catch (e) {}
    return jobs;
}

async function scrapeSaramin(keyword) {
    const encodedKeyword = encodeURIComponent(keyword);
    const url = `https://www.saramin.co.kr/zf_user/search?searchword=${encodedKeyword}&searchType=search&recruitPageCount=40`;
    const headers = { "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)", "Referer": "https://www.saramin.co.kr/" };
    const jobs = [];
    try {
        const response = await axios.get(url, { headers, timeout: 6000 });
        const $ = cheerio.load(response.data);
        $(".item_recruit").each((i, el) => {
            const item = $(el);
            const company = item.find(".corp_name a").text().trim() || "회사명 비공개";
            const jobAnchor = item.find(".job_tit a");
            if (!jobAnchor.length) return;
            const title = jobAnchor.text().trim();
            const link = jobAnchor.attr('href')?.startsWith('http') ? jobAnchor.attr('href') : "https://www.saramin.co.kr" + jobAnchor.attr('href');
            let address = "지역무관";
            let career = "관계없음";
            item.find(".job_condition span").each((idx, span) => {
                const text = $(span).text().trim();
                if (["서울", "경기", "인천", "충남", "부산", "대구", "전북", "경남", "경북", "전남", "충북", "세종", "울산", "대전", "광주", "제주", "강원"].some(loc => text.includes(loc))) {
                    address = text;
                } else if (text.includes("경력") || text.includes("신입")) {
                    career = text;
                }
            });
            jobs.push({ source: "사람인", company, title, address, career, education: "학력무관", detailText: item.text(), url: link });
        });
    } catch (e) {}
    return jobs;
}

async function scrapeJobKorea(keyword) {
    const encodedKeyword = encodeURIComponent(keyword);
    const url = `https://www.jobkorea.co.kr/Search/?stext=${encodedKeyword}`;
    const headers = { "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)" };
    const jobs = [];
    try {
        const response = await axios.get(url, { headers, timeout: 6000 });
        const $ = cheerio.load(response.data);
        $("div.rounded-2xl").each((i, el) => {
            const card = $(el);
            const titleAnchor = card.find("div.mb-0\\.5 a").first();
            if (!titleAnchor.length) return;
            const title = titleAnchor.text().trim();
            const link = titleAnchor.attr("href")?.startsWith("http") ? titleAnchor.attr("href") : "https://www.jobkorea.co.kr" + titleAnchor.attr("href");
            const company = card.find(".text-typo-b2-16").first().text().trim() || "회사명 비공개";
            const address = card.find(".text-typo-b4-14").first().text().trim() || "지역무관";
            jobs.push({ source: "잡코리아", company, title, address, career: "경력무관", education: "학력무관", detailText: card.text(), url: link });
        });
    } catch (e) {}
    return jobs;
}

