exports.code = async (inputs) => {
    let jobsList = findValueByKey(inputs, 'primary_jobs') || findValueByKey(inputs, 'primary_job');
    if (typeof jobsList === 'string') jobsList = jobsList.replace(/[\[\]'"]/g, '').trim();
    if (jobsList && !Array.isArray(jobsList)) jobsList = [jobsList];
    if (jobsList.length === 1 && jobsList[0].includes(',')) jobsList = jobsList[0].split(',').map(s => s.trim()).filter(Boolean);

    if (!jobsList || jobsList.length === 0 || jobsList[0] === '') {
    throw new Error("🚨 치명적 에러: 직무 키워드를 추출하지 못했습니다. 가짜 공고 발송을 차단하기 위해 스크래퍼를 강제 종료합니다.");
    }
    let rawKeywords = jobsList;
    const keywords = rawKeywords.map(kw => kw.trim());

    const currentUserEmail = findValueByKey(inputs, 'email') || '';
    const userRawAddress = findValueByKey(inputs, 'address') || '';

    let regionKeyword = "";
    if (userRawAddress) {
        const parts = userRawAddress.split(' ');
        let targetPart = parts.length > 1 ? parts[1] : parts[0];
        regionKeyword = targetPart.replace(/(시|구|군)$/, ''); 
    }

    const distVal = findValueByKey(inputs, 'max_distance') || findValueByKey(inputs, 'max_distance_km');
    const maxDistance = parseFloat(distVal) || 20.0; 
    const requiredCareer = findValueByKey(inputs, 'career') || '관계없음';
    const requiredEducation = findValueByKey(inputs, 'education') || '학력무관';

    const searchQueries = keywords.map(kw => regionKeyword ? `${kw} ${regionKeyword}` : kw);

    const crawlPromises = [];
    for (const query of searchQueries) {
        crawlPromises.push(scrapeWorknet(query));
        crawlPromises.push(scrapeIncruit(query));
        crawlPromises.push(scrapeSaramin(query));
        crawlPromises.push(scrapeJobKorea(query));
    }
    const allResults = await Promise.all(crawlPromises);
    const combinedJobs = allResults.flat();

    const seen = new Set();
    const uniqueCombinedJobs = combinedJobs.filter(j => {
        const duplicateKey = `${j.company}_${j.title}`;
        if (seen.has(duplicateKey)) return false;
        seen.add(duplicateKey);
        return true;
    });

    const matchedWorknet = [];
    const matchedIncruit = [];
    const matchedSaramin = [];
    const matchedJobkorea = [];
    const aiKeywords = ['ai', '인공지능', '러닝', 'gpt', 'llm', '머신러닝', '딥러닝'];

    const designKeywords = ['디자이너', '디자인', 'ui', 'ux', '시각', '콘텐츠', '그래픽', '인턴십'];
    const developerKeywords = ['엔지니어', '개발자', '기획자', 'developer', 'engineer', '퍼블리셔', 'publisher', '백엔드', 'backend', '클라우드', 'cloud', '운영'];

    for (const j of uniqueCombinedJobs) {
        const jobAddress = j.address;
        const titleLower = j.title.toLowerCase();

        const isDesignJob = designKeywords.some(k => titleLower.includes(k));
        const isDevOrPlannerJob = developerKeywords.some(k => titleLower.includes(k));

        // 직무 필터링: '디자인' 키워드가 들어올 때만 작동하도록 제한하여, 
        // Java, 백엔드 등 타 직무 검색 시에는 필터가 오작동하지 않고 패스되도록 설계
        if (keywords.some(kw => kw.includes('디자인')) && (!isDesignJob || isDevOrPlannerJob)) {
            continue; 
        }

        const isRemote = jobAddress.includes("지역무관") || jobAddress.includes("재택") || jobAddress.includes("전국") || jobAddress.includes("전역") || jobAddress.includes("전체");

        // 💡 [인크루트 주소 온전 반영] 이제 jobAddress에 "강남구"가 온전히 살아있으므로 정상 통과됨
        if (!isRemote && regionKeyword && !jobAddress.includes(regionKeyword)) {
            continue; 
        }

        if (requiredCareer !== "관계없음") {
            if (requiredCareer === "신입" && !j.career.includes("신입") && !j.career.includes("무관")) continue;
            if (requiredCareer === "경력" && !j.career.includes("경력") && !j.career.includes("년")) continue;
        }

        if (requiredEducation !== "학력무관") {
            const detail = (j.detailText || "").replace(/\s/g, ''); // 띄어쓰기 무시하고 검사
            const isAnyEdu = detail.includes("학력무관") || detail.includes("무관");

            if (!isAnyEdu) {
                if (requiredEducation === "고졸") {
                    // 고졸자는 '대졸', '초대졸', '전문대' 단어가 들어간 (고학력 요구) 공고 지원 불가
                    if (detail.includes("대졸") || detail.includes("초대졸") || detail.includes("전문대") || detail.includes("대학교") || detail.includes("석사")) {
                        continue;
                    }
                } else if (requiredEducation === "대졸23") {
                    // 2,3년제 졸업자는 '4년제', '석사' 단어가 들어간 공고 지원 불가
                    if (detail.includes("4년") || detail.includes("석사")) {
                        continue;
                    }
                }
            }
        }

        const isAiRelated = aiKeywords.some(kw => titleLower.includes(kw) || (j.detailText && j.detailText.toLowerCase().includes(kw)));
        const displayTitle = isAiRelated ? `🔥 [AI우대] ${j.title}` : j.title;

        const processedJob = {
            company: j.company,
            title: displayTitle,
            address: j.address,
            career: j.career,
            education: j.education,
            isAi: isAiRelated,
            distance: isRemote ? "재택/지역무관" : `위치 일치`,
            url: j.url
        };

        if (j.source === "고용24") matchedWorknet.push(processedJob);
        else if (j.source === "인크루트") matchedIncruit.push(processedJob);
        else if (j.source === "사람인") matchedSaramin.push(processedJob);
        else if (j.source === "잡코리아") matchedJobkorea.push(processedJob);
    }

    const getTopFive = (jobs) => jobs.sort((a, b) => (b.isAi ? 1 : 0) - (a.isAi ? 1 : 0)).slice(0, 5);

    const displayWorknet = getTopFive(matchedWorknet);
    const displayIncruit = getTopFive(matchedIncruit);
    const displaySaramin = getTopFive(matchedSaramin);
    const displayJobkorea = getTopFive(matchedJobkorea);

    const buildHtmlList = (jobs) => {
        let listHtml = "";
        for (const j of jobs) {
            listHtml += `
            <li style="margin-bottom: 10px; list-style: none; padding: 12px; border-bottom: 1px solid #f3f4f6; font-family: sans-serif; background-color: #fafafa; border-radius: 6px;">
                <strong style="color: #4f46e5; font-size: 1.2em;">${j.company}</strong><br>
                <a href="${j.url}" target="_blank" style="text-decoration: none; color: #1e293b; font-weight: bold; font-size: 1.15em; line-height: 1.4; display: inline-block; margin-top: 2px;">${j.title}</a><br>
                <span style="color: #64748b; font-size: 1.0em; display: inline-block; margin-top: 4px;">📍 ${j.address} | 💼 ${j.career}</span>
            </li>`;
        }
        return listHtml;
    };

    const worknetListHtml = buildHtmlList(displayWorknet);
    const incruitListHtml = buildHtmlList(displayIncruit);
    const saraminListHtml = buildHtmlList(displaySaramin);
    const jobkoreaListHtml = buildHtmlList(displayJobkorea);

    const totalCount = matchedWorknet.length + matchedIncruit.length + matchedSaramin.length + matchedJobkorea.length;

    const searchCombo = searchQueries[0];
    const encodedKW = encodeURIComponent(searchCombo);

    const worknetSearchLink = `https://www.work.go.kr/empInfo/empInfoSrch/list/dtlEmpSrchList.do?searchOn=Y&srcKeyword=${encodedKW}`;
    const incruitSearchLink = `https://search.incruit.com/list/search.asp?col=job&kw=${encodedKW}`;
    const saraminSearchLink = `https://www.saramin.co.kr/zf_user/search?searchword=${encodedKW}`;
    const jobkoreaSearchLink = `https://www.jobkorea.co.kr/Search/?stext=${encodedKW}`;

    const myVercelDomain = "project-alicetest1.vercel.app";
    const unsubscribeLink = `https://${myVercelDomain}/unsubscribe.html?email=${encodeURIComponent(currentUserEmail)}`;
    const modifyLink = `https://${myVercelDomain}`;

    let mailBody = `
    <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto; padding: 15px; background-color: #ffffff; border-radius: 12px; border: 1px solid #e2e8f0; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);">
        <h2 style="color: #0f172a; border-bottom: 2px solid #4f46e5; padding-bottom: 10px; margin-top: 0; font-size: 1.45em;">📢 AI 채용 큐레이션 데일리 리포트</h2>

        <p style="color: #475569; font-size: 1.1em; line-height: 1.5; margin-bottom: 20px;">
            AI 분석 직무 키워드 [<strong>${keywords.join(', ')}</strong>] 및 희망 주소 [<strong>${userRawAddress}</strong>] 기준 <strong>반경 ${maxDistance}km 이내</strong> 추천 공고입니다. (총 <strong>${totalCount}건</strong> 매칭 완료)
        </p>

        <div style="margin-bottom: 20px; font-size: 1.05em; color: #475569; font-weight: bold;">
            🔵 워크넷: ${matchedWorknet.length}건 | 🟢 인크루트: ${matchedIncruit.length}건 | 🟠 사람인: ${matchedSaramin.length}건 | 🟡 잡코리아: ${matchedJobkorea.length}건
        </div>

        <div id="worknet-section" style="margin-bottom: 30px; border-top: 1px solid #e2e8f0; padding-top: 20px;">
            <h3 style="color: #1e40af; background-color: #eff6ff; padding: 8px 12px; border-radius: 6px; font-size: 1.2em; margin-top: 0; margin-bottom: 15px; border-left: 4px solid #3b82f6;">🔵 고용24 (워크넷) 추천 공고 (상위 5개)</h3>
            ${worknetListHtml ? `<ul style="padding: 0; margin: 0;">${worknetListHtml}</ul>` : `<p style="color: #94a3b8; font-size: 1.0em; margin: 0; padding: 12px;">조건 매칭 공고가 없습니다.</p>`}
            <div style="text-align: center; margin-top: 15px;">
                <a href="${worknetSearchLink}" target="_blank" style="display: inline-block; padding: 8px 16px; background-color: #3b82f6; color: white; text-decoration: none; font-weight: bold; font-size: 1.0em; border-radius: 6px;">👉 고용24 결과 전체 보기</a>
            </div>
        </div>

        <div id="incruit-section" style="margin-bottom: 30px; border-top: 1px solid #e2e8f0; padding-top: 20px;">
            <h3 style="color: #065f46; background-color: #ecfdf5; padding: 8px 12px; border-radius: 6px; font-size: 1.2em; margin-top: 0; margin-bottom: 15px; border-left: 4px solid #10b981;">🟢 인크루트 추천 공고 (상위 5개)</h3>
            ${incruitListHtml ? `<ul style="padding: 0; margin: 0;">${incruitListHtml}</ul>` : `<p style="color: #94a3b8; font-size: 1.0em; margin: 0; padding: 12px;">조건 매칭 공고가 없습니다.</p>`}
            <div style="text-align: center; margin-top: 15px;">
                <a href="${incruitSearchLink}" target="_blank" style="display: inline-block; padding: 8px 16px; background-color: #10b981; color: white; text-decoration: none; font-weight: bold; font-size: 1.0em; border-radius: 6px;">👉 인크루트 결과 전체 보기</a>
            </div>
        </div>

        <div id="saramin-section" style="margin-bottom: 30px; border-top: 1px solid #e2e8f0; padding-top: 20px;">
            <h3 style="color: #c2410c; background-color: #fff7ed; padding: 8px 12px; border-radius: 6px; font-size: 1.2em; margin-top: 0; margin-bottom: 15px; border-left: 4px solid #f97316;">🟠 사람인 추천 공고 (상위 5개)</h3>
            ${saraminListHtml ? `<ul style="padding: 0; margin: 0;">${saraminListHtml}</ul>` : `<p style="color: #94a3b8; font-size: 1.0em; margin: 0; padding: 12px;">조건 매칭 공고가 없습니다.</p>`}
            <div style="text-align: center; margin-top: 15px;">
                <a href="${saraminSearchLink}" target="_blank" style="display: inline-block; padding: 8px 16px; background-color: #f97316; color: white; text-decoration: none; font-weight: bold; font-size: 1.0em; border-radius: 6px;">👉 사람인 결과 전체 보기</a>
            </div>
        </div>

        <div id="jobkorea-section" style="margin-bottom: 30px; border-top: 1px solid #e2e8f0; padding-top: 20px;">
            <h3 style="color: #854d0e; background-color: #fef9c3; padding: 8px 12px; border-radius: 6px; font-size: 1.2em; margin-top: 0; margin-bottom: 15px; border-left: 4px solid #eab308;">🟡 잡코리아 추천 공고 (상위 5개)</h3>
            ${jobkoreaListHtml ? `<ul style="padding: 0; margin: 0;">${jobkoreaListHtml}</ul>` : `<p style="color: #94a3b8; font-size: 1.0em; margin: 0; padding: 12px;">조건 매칭 공고가 없습니다.</p>`}
            <div style="text-align: center; margin-top: 15px;">
                <a href="${jobkoreaSearchLink}" target="_blank" style="display: inline-block; padding: 8px 16px; background-color: #eab308; color: white; text-decoration: none; font-weight: bold; font-size: 1.0em; border-radius: 6px;">👉 잡코리아 결과 전체 보기</a>
