        <div style="text-align: center; margin-top: 20px; font-size: 14px; border-top: 1px dashed #cbd5e1; padding-top: 15px;">
            <a href="${modifyLink}" target="_blank" style="color: #4f46e5; text-decoration: none; font-weight: bold;">[내 조건 변경]</a> | 
            <a href="${unsubscribeLink}" target="_blank" style="color: #dc3545; text-decoration: underline; font-weight: bold;">[수신 거부 (구독 취소)]</a>
        </div>
    </div>`;

    return { status: "success", jobs: [ ...matchedWorknet, ...matchedIncruit, ...matchedSaramin, ...matchedJobkorea ], mail_body: mailBody };
